import React from "react";

const statusEmoji = {
  PENDING: "🟡",
  COMPLETED: "🟢",
  MISSED: "🔴",
};

const statusColor = {
  PENDING: "#fff8e1",
  COMPLETED: "#e8f5e9",
  MISSED: "#ffebee",
};

function TaskCard({ task, onComplete }) {
  return (
    <div style={{
      background: statusColor[task.todayStatus],
      border: "1px solid #ddd",
      borderRadius: "8px",
      padding: "16px",
      marginBottom: "12px",
      width: "300px",
    }}>
      <h3 style={{ margin: "0 0 8px 0" }}>{task.scheduledTime}</h3>
      <p style={{ margin: "0 0 8px 0", fontWeight: "bold" }}>{task.title}</p>
      <p style={{ margin: "0 0 12px 0" }}>{task.description}</p>
      <p>Status: {statusEmoji[task.todayStatus]} {task.todayStatus}</p>
      {task.todayStatus === "PENDING" && (
        <button
          onClick={() => onComplete(task.id)}
          style={{
            background: "#4caf50",
            color: "white",
            border: "none",
            padding: "8px 16px",
            borderRadius: "4px",
            cursor: "pointer",
          }}
        >
          Complete
        </button>
      )}
    </div>
  );
}

export default TaskCard;
